import{_ as i,c as e,o as l,ae as o}from"./chunks/framework.D4x4JNJ3.js";const m=JSON.parse('{"title":"版本更新日志 v2026.1.x","description":"","frontmatter":{"title":"版本更新日志 v2026.1.x"},"headers":[],"relativePath":"zh/changelog/v2026.1.x.md","filePath":"zh/changelog/v2026.1.x.md","lastUpdated":1772156751000}'),t={name:"zh/changelog/v2026.1.x.md"};function n(r,a,d,c,s,h){return l(),e("div",null,[...a[0]||(a[0]=[o('<h1 id="mogan-stem-v2026-1-x-版本更新日志" tabindex="-1">Mogan STEM v2026.1.x 版本更新日志 <a class="header-anchor" href="#mogan-stem-v2026-1-x-版本更新日志" aria-label="Permalink to “Mogan STEM v2026.1.x 版本更新日志”">​</a></h1><blockquote><p>说明：Liii STEM 是 Mogan STEM 的商业版，会在开源版的基础上提供账号登录、AI 等增值能力。更多细节见Liii STEM：<a href="https://liiistem.cn/docs/changelog-v2026.1.x.html" target="_blank" rel="">v2026.1.x</a></p></blockquote><h2 id="⭐️-全新功能和亮点" tabindex="-1">⭐️ 全新功能和亮点 <a class="header-anchor" href="#⭐️-全新功能和亮点" aria-label="Permalink to “⭐️ 全新功能和亮点”">​</a></h2><ol><li><strong>魔法粘贴增强与（Liii STEM）Math OCR</strong>：支持无损粘贴网页/对话内容；（Liii STEM）支持图片/截图/手写公式、PDF 论文中的公式识别，并可快速粘贴为 Liii STEM 格式。</li><li><strong>选择性粘贴</strong>：支持从剪贴板自动检测格式，并按需粘贴 Markdown / LaTeX / HTML 等（<code>Ctrl</code> + <code>Alt</code> + <code>V</code> / <code>Command</code> + <code>Option</code> + <code>V</code>）。</li><li><strong>（Liii STEM）AI 模型扩展</strong>：新增 GLM-4.6V 与 Kimi-K2.5 大模型，提升 AI 辅助写作与对话能力。</li><li><strong>表格能力增强</strong>：表格内部网格线支持鼠标拖动；新增三线表功能，表格排版更高效。</li><li><strong>结构化搜索与替换</strong>：支持文本、公式、符号、矩阵等结构内容的搜索与替换。</li><li><strong>全新批注功能</strong>：菜单栏新增“批注”，支持为文档添加可折叠/展开的批注；批注内容支持文字与公式等。</li><li><strong>代码语法高亮</strong>：新增 R / SQL / Bash 语法高亮。</li><li><strong>学术写作支持</strong>：参考文献支持 GBT7714-2015。</li></ol><h2 id="🌟-总结" tabindex="-1">🌟 总结 <a class="header-anchor" href="#🌟-总结" aria-label="Permalink to “🌟 总结”">​</a></h2><p>Mogan STEM v2026.1.x 版本围绕 <strong>魔法粘贴</strong> 持续打磨：选择性粘贴覆盖 Markdown/LaTeX/HTML 等格式；表格能力补齐（网格线拖动、三线表），并完善结构化搜索替换与批注功能，同时新增多种代码语法高亮与参考文献国标支持并修复多项稳定性问题。商业版 Liii STEM 在此基础上提供 Math OCR 与 AI 大模型等增值能力。</p><h2 id="🔧-更新日志" tabindex="-1">🔧 更新日志 <a class="header-anchor" href="#🔧-更新日志" aria-label="Permalink to “🔧 更新日志”">​</a></h2><h3 id="mogan-stem-v2026-1-2-2026-01-23" tabindex="-1">Mogan STEM v2026.1.2 (2026/01/23) <a class="header-anchor" href="#mogan-stem-v2026-1-2-2026-01-23" aria-label="Permalink to “Mogan STEM v2026.1.2 (2026/01/23)”">​</a></h3><ol><li>新增 SQL 语言语法高亮。</li><li>新增 Bash 语言语法高亮。</li><li>修复 Tab Cycling 在缩放时的位置异常。</li><li>修复大根号显示撕裂问题。</li></ol><h3 id="mogan-stem-v2026-1-1-2026-01-16" tabindex="-1">Mogan STEM v2026.1.1 (2026/01/16) <a class="header-anchor" href="#mogan-stem-v2026-1-1-2026-01-16" aria-label="Permalink to “Mogan STEM v2026.1.1 (2026/01/16)”">​</a></h3><ol><li>魔法粘贴增强：支持无损粘贴网页/对话内容；文本模式（Liii STEM）支持图片 OCR；数学模式支持 LaTeX 转 Mogan STEM。</li><li>选择性粘贴：可选择粘贴 Markdown / LaTeX / HTML 等格式，并支持图片 OCR 为公式（Liii STEM）。</li><li>结构化搜索与替换：支持文本、公式、符号、矩阵等结构内容的搜索与替换。</li><li>全新批注功能：支持折叠/展开批注，批注内容支持文字与公式等。</li><li>黑夜模式：界面与文档均支持黑夜模式。</li><li>排版引擎优化：中文标点压缩。</li><li>表格增强：支持表格内部网格线鼠标拖动。</li><li>Tab Cycling 增强：新增 <code>mathcal</code> / <code>mathbf</code> / <code>mathfrak</code>/ <code>mathscr</code>/ <code>mathbbm</code>，为 <code>n</code> 增加 <code>\\nabla</code> 变体。</li><li>图片悬浮菜单：支持快速调整图片布局与（Liii STEM）OCR 识别。</li><li><code>nbsp</code> 显示优化：不换行空格默认采用不可见颜色，可调整。</li><li>新增 R 语言语法高亮。</li><li>参考文献支持 GBT7714-2015。</li></ol><h2 id="👏-加入社区" tabindex="-1">👏 加入社区 <a class="header-anchor" href="#👏-加入社区" aria-label="Permalink to “👏 加入社区”">​</a></h2><ul><li>墨干社区 QQ 群：934456971</li><li>Discord 群组：<a href="https://discord.gg/Q7xARnAf8t" target="_blank" rel="">https://discord.gg/Q7xARnAf8t</a></li><li>官网：<a href="https://mogan.app/" target="_blank" rel="">https://mogan.app/</a></li></ul>',13)])])}const M=i(t,[["render",n]]);export{m as __pageData,M as default};
